import sys

def main():
    input = sys.stdin.read
    data = input().split()

    H = int(data[0])
    W = int(data[1])
    K = int(data[2])
    grid = data[3:3+H]

    min_ops = float('inf')

    # Check rows
    for i in range(H):
        row = grid[i]
        for j in range(W - K + 1):
            ops = 0
            valid = True
            for k in range(K):
                cell = row[j + k]
                if cell == 'x':
                    valid = False
                    break
                elif cell == '.':
                    ops += 1
            if valid and ops < min_ops:
                min_ops = ops

    # Check columns
    for j in range(W):
        for i in range(H - K + 1):
            ops = 0
            valid = True
            for k in range(K):
                cell = grid[i + k][j]
                if cell == 'x':
                    valid = False
                    break
                elif cell == '.':
                    ops += 1
            if valid and ops < min_ops:
                min_ops = ops

    if min_ops == float('inf'):
        print(-1)
    else:
        print(min_ops)

if __name__ == "__main__":
    main()
